$pageTitle='Membership Checkout';$pageDescription='Complete Stonefellow membership checkout.';$pageClass='membership-page billing-page';require __DIR__.'/includes/billing_checkout_runtime.php';$user=sf_require_login();$token=trim((string)($_GET['token']??$_POST['token']??''));$checkout=$token!==''?sf_billing_checkout_by_token($token):null;if(!$checkout||(int)($checkout['user_id']??0)!==(int)$user['id']){sf_auth_flash('error','Checkout session was not found.');sf_redirect(sf_url('subscribe.php'));}$provider=(string)($checkout['provider']??'sandbox');$sandbox=$provider==='sandbox'&&sf_revenue_sandbox_allowed('subscription');if(($_SERVER['REQUEST_METHOD']??'GET')==='POST'){if(!sf_verify_csrf($_POST['csrf_token']??null))sf_auth_flash('error','Security check failed.');elseif(($_POST['action']??'')==='complete'){if(!$sandbox)sf_auth_flash('error','Local completion is disabled for this checkout.');else{$result=sf_billing_complete_provider_checkout($token,['provider'=>'sandbox','verified'=>true,'provider_payment_id'=>'sandbox_pay_'.substr(hash('sha256',$token),0,24),'amount_cents'=>(int)$checkout['amount_cents'],'currency'=>(string)$checkout['currency'],'payment_status'=>'paid']);if(!empty($result['ok']))sf_redirect(sf_url('billing-success.php?token='.urlencode($token)));sf_auth_flash('error',(string)($result['message']??'Payment failed.'));}}elseif(($_POST['action']??'')==='cancel'){sf_billing_cancel_checkout($token);sf_redirect(sf_url('billing-cancel.php?token='.urlencode($token)));}$checkout=sf_billing_checkout_by_token($token);}$expired=!empty($checkout['expires_at'])&&strtotime((string)$checkout['expires_at'])<time();$hosted=$provider==='stripe'?sf_billing_checkout_hosted_url($checkout):'';require __DIR__.'/includes/header.php';
